/* --- UI Helpers --- */
function Note({ children }: { children: React.ReactNode }) {
  return <div className="flex gap-3 bg-card border border-border rounded-[14px] p-4 text-[14px] shadow-sm my-4 transition-colors"><Info className="h-4 w-4 mt-0.5 shrink-0 text-primary" /><div className="text-muted-foreground leading-relaxed">{children}</div></div>;
}
function Tip({ children }: { children: React.ReactNode }) {
  return <div className="flex gap-3 bg-card border border-border rounded-[14px] p-4 text-[14px] shadow-sm my-4 transition-colors"><Lightbulb className="h-4 w-4 mt-0.5 shrink-0 text-primary" /><div className="text-muted-foreground leading-relaxed">{children}</div></div>;
}
function Warn({ children }: { children: React.ReactNode }) {
  return <div className="flex gap-3 bg-card border border-border rounded-[14px] p-4 text-[14px] shadow-sm my-4 transition-colors"><AlertTriangle className="h-4 w-4 mt-0.5 shrink-0 text-primary" /><div className="text-muted-foreground leading-relaxed">{children}</div></div>;
}
function CodeBlock({ children }: { children: string }) {
  return <pre className="bg-muted text-foreground p-4 rounded-lg font-mono text-sm overflow-x-auto leading-relaxed border border-border">{children}</pre>;
}

